import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { link } from 'decantr/router';
import { Button, icon, Badge } from 'decantr/components';

code.example:
function VacancyTracker({ units, applicants }) {
  const { div, h1, h2, span, table, thead, tbody, tr, th, td } = tags;
  const vacantUnits = units.filter(u => u.status === 'vacant');
  const totalUnits = units.length;
  const vacancyRate = Math.round((vacantUnits.length / totalUnits) * 100);
  const avgDaysVacant = Math.round(vacantUnits.reduce((sum, u) => sum + u.daysVacant, 0) / vacantUnits.length) || 0;
  const monthlyLostRevenue = vacantUnits.reduce((sum, u) => sum + u.marketRent, 0);

  return div({ class: css('_flex _col _gap6') },
    div({ class: css('_flex _jcsb _aic') },
      div({},
        h1({ class: css('_heading3') }, 'Vacancy Tracker'),
        span({ class: css('_textsm _fgmuted') }, `${vacantUnits.length} of ${totalUnits} units vacant`)
      ),
      Button({ variant: 'primary' }, icon('megaphone'), 'Create Listing')
    ),
    div({ class: css('_grid _cols4 _gap4') },
      div({ class: css('estate-card-metric _p4') },
        span({ class: css('_heading2 _block _fgdanger') }, `${vacancyRate}%`),
        span({ class: css('_textsm _fgmuted') }, 'Vacancy Rate')
      ),
      div({ class: css('estate-card-metric _p4') },
        span({ class: css('_heading2 _block') }, vacantUnits.length),
        span({ class: css('_textsm _fgmuted') }, 'Vacant Units')
      ),
      div({ class: css('estate-card-metric _p4') },
        span({ class: css('_heading2 _block') }, avgDaysVacant),
        span({ class: css('_textsm _fgmuted') }, 'Avg Days Vacant')
      ),
      div({ class: css('estate-card-metric _p4') },
        span({ class: css('_heading2 _block _fgdanger') }, `$${monthlyLostRevenue.toLocaleString()}`),
        span({ class: css('_textsm _fgmuted') }, 'Monthly Lost Revenue')
      )
    ),
    div({ class: css('estate-card _p0 _overflow[hidden]') },
      div({ class: css('_p4 _borderB') },
        h2({ class: css('_heading5') }, 'Vacant Units')
      ),
      div({ class: css('estate-table _overflow[auto]') },
        table({ class: css('_wfull') },
          thead({},
            tr({ class: css('_bgSurface') },
              th({ class: css('_p3 _textleft _font500') }, 'Property'),
              th({ class: css('_p3 _textleft _font500') }, 'Unit'),
              th({ class: css('_p3 _textleft _font500') }, 'Specs'),
              th({ class: css('_p3 _tr _font500') }, 'Market Rent'),
              th({ class: css('_p3 _tc _font500') }, 'Days Vacant'),
              th({ class: css('_p3 _tc _font500') }, 'Listed'),
              th({ class: css('_p3 _tc _font500') }, 'Showings'),
              th({ class: css('_p3 _tc _font500') }, 'Applicants'),
              th({ class: css('_p3') })
            )
          ),
          tbody({},
            ...vacantUnits.map((u, i) =>
              tr({ class: css(i % 2 === 0 ? '' : '_bgSurfaceRaised') },
                td({ class: css('_p3 _textsm') }, u.propertyName),
                td({ class: css('_p3 _font500') }, `Unit ${u.unitNumber}`),
                td({ class: css('_p3 _textsm _fgmuted') }, `${u.beds}bd / ${u.baths}ba`),
                td({ class: css('_p3 _tr _font500') }, `$${u.marketRent.toLocaleString()}`),
                td({ class: css(`_p3 _tc ${u.daysVacant > 30 ? '_fgdanger' : ''}`) }, u.daysVacant),
                td({ class: css('_p3 _tc') }, Badge({ variant: u.listed ? 'success' : 'default' }, u.listed ? 'Listed' : 'Unlisted')),
                td({ class: css('_p3 _tc') }, u.showings || 0),
                td({ class: css('_p3 _tc') }, u.applicants || 0),
                td({ class: css('_p3') },
                  div({ class: css('_flex _gap1') },
                    u.listed ? null : Button({ variant: 'ghost', size: 'sm' }, icon('megaphone', { size: '14' })),
                    link({ href: `/properties/${u.propertyId}/units/${u.id}` },
                      Button({ variant: 'ghost', size: 'sm' }, icon('chevron-right', { size: '14' }))
                    )
                  )
                )
              )
            )
          )
        )
      )
    ),
    applicants?.length > 0 ? div({ class: css('estate-card _p0 _overflow[hidden]') },
      div({ class: css('_p4 _borderB _flex _jcsb _aic') },
        h2({ class: css('_heading5') }, 'Applicant Pipeline'),
        span({ class: css('_textsm _fgmuted') }, `${applicants.length} applicants`)
      ),
      div({ class: css('_flex _col') },
        ...applicants.map(a =>
          div({ class: css('_flex _aic _gap4 _p4 _borderB _last:borderB0') },
            div({ class: css('_flex1') },
              span({ class: css('_font500 _block') }, a.name),
              span({ class: css('_textsm _fgmuted') }, `Applied for Unit ${a.unitNumber} at ${a.propertyName}`)
            ),
            Badge({ variant: a.status === 'approved' ? 'success' : a.status === 'pending' ? 'warning' : 'default' }, a.status),
            span({ class: css('_textsm _fgmuted') }, new Date(a.appliedDate).toLocaleDateString()),
            Button({ variant: 'outline', size: 'sm' }, 'Review')
          )
        )
      )
    ) : null
  );
}

