function VacancyMini({ vacancyRate, vacantCount, lostRevenue }) {
  const { div, span } = tags;

  return link({ href: '/vacancies', class: css('estate-card _p4 _hoverShadow _trans') },
    div({ class: css('_flex _jcsb _aic _mb3') },
      span({ class: css('_heading6') }, 'Vacancies'),
      span({ class: css(`_heading4 ${vacancyRate > 10 ? '_fgdanger' : '_fgsuccess'}`) }, `${vacancyRate}%`)
    ),
    div({ class: css('_grid _cols2 _gap4') },
      div({},
        span({ class: css('_heading4 _block') }, vacantCount),
        span({ class: css('_textxs _fgmuted') }, 'Vacant Units')
      ),
      div({},
        span({ class: css('_heading4 _block _fgdanger') }, `$${lostRevenue.toLocaleString()}`),
        span({ class: css('_textxs _fgmuted') }, 'Lost/Month')
      )
    )
  );
}

